return new Promise((resolve, reject) => {
    const hashfile = crypto.createHash(method);
    const stream = fs.createReadStream(filepath);

    stream.on("data", chunk => hashfile.update(chunk));
    stream.on("end", () => {
        const digestBase64 = hashfile.digest("base64");

        if (digestBase64 == hashing || hashing == 0) {
            msg.payload = true;

            // If rename-to-date is true, move file to date-based directory
            if (renameToDate && msg.wnmpubtime) {
                try {
                    // Get base directory and filename
                    const baseDir = path.dirname(filepath);
                    const filename = path.basename(filepath);

                    // Create date-based path from RFC3339
                    const formatted = new Date(msg.wnmpubtime).toISOString().slice(0, 13).replace('T', '/').replace(/-/g, '/');
                    const dateDir = path.join(baseDir, formatted);

                    // Create directory recursively
                    fs.mkdirSync(dateDir, { recursive: true });

                    // New file path
                    const newFilepath = path.join(dateDir, filename);

                    // Move file (same filesystem)
                    fs.renameSync(filepath, newFilepath);

                    // Update filepath to new location
                    filepath = newFilepath;
                } catch (err) {
                    node.error("Failed to move file to date directory: " + err.message);
                    reject(msg);
                    return;
                }
            }
            // If rename-to-topic is true, move file to topic-based directory
            else if (renameToTopic && msg.wnmtopic) {
                try {
                    // Get base directory and filename
                    const baseDir = path.dirname(filepath);
                    const filename = path.basename(filepath);

                    // Parse topic: cache/a/wis2/centre-id/... or origin/a/wis2/centre-id/...
                    // Remove first 3 levels (cache/a/wis2 or origin/a/wis2)
                    const topicParts = msg.wnmtopic.split('/');
                    const relevantParts = topicParts.slice(3); // Skip first 3 levels
                    const topicPath = relevantParts.join('/');

                    const topicDir = path.join(baseDir, topicPath);

                    // Create directory recursively
                    fs.mkdirSync(topicDir, { recursive: true });

                    // New file path
                    const newFilepath = path.join(topicDir, filename);

                    // Move file (same filesystem)
                    fs.renameSync(filepath, newFilepath);

                    // Update filepath to new location
                    filepath = newFilepath;
                } catch (err) {
                    node.error("Failed to move file to topic directory: " + err.message);
                    reject(msg);
                    return;
                }
            }

            msg.localhref = download + "/" + worker + filepath;
            resolve(msg);
        } else {
            msg.payload = false;
            fs.unlink(filepath, (err) => {
                if (err) {
                    node.error("Failed to delete file with incorrect hash: " + err.message);
                }
                resolve(msg);
            });
        }
    });
    stream.on("error", err => {
        node.error("Failed to read or hash the file: " + err.message);
        msg.payload = null;
        reject(msg);
    });
});

