                    "labels": {
                        "report_by": global_cache
                    }
                }
            };

            // Output 5: Total Length
            const total2 = {
                payload: {
                    "op": "inc",
                    "val": totalLength,
                    "labels": {
                        "report_by": global_cache
                    }                }
            };

            // Output 6: Average Delay
            const total3 = {
                payload: {
                    "op": "set",
                    "val": avgDelay,
                    "labels": {
                        "report_by": global_cache
                    }                }
            };

            // Send total stats on outputs 4, 5, 6
            node.send([null, null, null, total1, total2, total3]);
        });
    })
    .catch(err => {
        node.error('Redis read error: ' + err);
    });

return null;

// First, convert array to object
const arr = msg.payload;
const output = {};

for (let i = 0; i < arr.length; i += 2) {
    const key = String(arr[i]);
    const value = arr[i + 1];
    output[key] = value;
}

// Extract length from wnm
let length = null;
if (output.wnm) {
    try {
        const wnmObj = JSON.parse(output.wnm);
        if (wnmObj.links && wnmObj.links.length > 0) {
            // Get length from first link (links[0])
            if (wnmObj.links[0].length) {
                length = wnmObj.links[0].length;
            }
        }
    } catch (e) {
        // Failed to parse wnm
    }
}

// Compute difference between stored and published
let delay = null;
if (output.stored && output.published) {
    delay = parseInt(output.stored) - parseInt(output.published);
}

// Extract centre-id (4th value when split by /)
let centreId = null;
if (output.topic) {
    const topicParts = output.topic.split('/');
    if (topicParts.length >= 4) {
        centreId = topicParts[3];  // Index 3 is the 4th value
    }
}

// Extract subtopic (from 7th value onwards)
let subtopic = null;
if (output.topic) {
    const topicParts = output.topic.split('/');
    if (topicParts.length >= 6) {
        subtopic = topicParts.slice(5).join('/');  // Index 6 onwards (7th value+)
    }
}

// Add extracted values to output
output.length = length;
output.delay = delay;
output.centreId = centreId;
output.subtopic = subtopic;

msg.payload = output;
return msg;

const cluster = global.get('redisCluster');

if (!cluster) {
    node.error('Redis cluster not connected');
    return null;
}

const data = msg.payload;
const windowKey = flow.get('hashstat'); // Get current window from flow context

const multi = cluster.multi();

// All use {windowKey} hash tag - Overall stats
multi.hincrby(`{${windowKey}}:total`, 'count', 1);
multi.hincrby(`{${windowKey}}:total`, 'totalLength', data.length);
multi.hincrby(`{${windowKey}}:total`, 'totalDelay', data.delay);

// Stats per combo (centre + subtopic)
multi.hincrby(`{${windowKey}}:combo:${data.centreId}:${data.subtopic}`, 'count', 1);
multi.hincrby(`{${windowKey}}:combo:${data.centreId}:${data.subtopic}`, 'totalLength', data.length);
multi.hincrby(`{${windowKey}}:combo:${data.centreId}:${data.subtopic}`, 'totalDelay', data.delay);

// Set expiry on keys (1 hour)
multi.expire(`{${windowKey}}:total`, 3600);
multi.expire(`{${windowKey}}:combo:${data.centreId}:${data.subtopic}`, 3600);

multi.exec()
    .then(results => {
        msg.payload = { success: true, commands: results.length };
        node.send(msg);
    })
    .catch(err => {
        node.error('Redis write error: ' + err);
    });

return null;
